import { forwardRef } from "react";
import {
  CheckboxGroup as AriaCheckboxGroup,
  type CheckboxGroupProps as AriaCheckboxGroupProps,
  CheckboxGroupStateContext,
} from "react-aria-components";

// Re-export context for use by child components (CheckboxItem, Checkbox, CheckboxTile)
export { CheckboxGroupStateContext };

interface CheckboxGroupCustomProps {
  /**
   * The current selected values (controlled).
   * Pass an array of checkbox `value` strings.
   */
  value?: string[];

  /**
   * The default selected values (uncontrolled).
   * Pass an array of checkbox `value` strings.
   */
  defaultValue?: string[];

  /**
   * Handler called when the selection changes.
   * Receives an array of currently selected values.
   */
  onChange?: (value: string[]) => void;

  /**
   * Whether all checkboxes in the group are disabled.
   * @default false
   */
  disabled?: boolean;

  /**
   * Whether the checkbox group is in an invalid/error state.
   * When true, all checkboxes in the group show error styling.
   * @default false
   */
  invalid?: boolean;

  /**
   * Whether at least one checkbox must be selected.
   * @default false
   */
  required?: boolean;

  /**
   * Whether the checkbox group is read-only.
   * @default false
   */
  readOnly?: boolean;

  /**
   * The name of the checkbox group, used when submitting an HTML form.
   */
  name?: string;

  /**
   * The axis the checkboxes should align with.
   * @default 'vertical'
   */
  orientation?: "horizontal" | "vertical";
}

// Props that we rename from HTML-style to React Aria's is-prefixed style
type RenamedAriaProps =
  | "isDisabled"
  | "isInvalid"
  | "isRequired"
  | "isReadOnly";

export interface CheckboxGroupProps
  extends
    Omit<
      AriaCheckboxGroupProps,
      keyof CheckboxGroupCustomProps | RenamedAriaProps
    >,
    CheckboxGroupCustomProps {}

/**
 * CheckboxGroup manages a collection of Checkbox or CheckboxItem components,
 * handling selection state, validation, and accessibility.
 *
 * @example
 * // Controlled
 * const [selected, setSelected] = useState(['option1']);
 *
 * <CheckboxGroup value={selected} onChange={setSelected} aria-label="Options">
 *   <Checkbox value="option1" label={{ children: "Option 1" }} />
 *   <Checkbox value="option2" label={{ children: "Option 2" }} />
 * </CheckboxGroup>
 *
 * @example
 * // Uncontrolled
 * <CheckboxGroup defaultValue={['option1']} aria-label="Options">
 *   <Checkbox value="option1" label={{ children: "Option 1" }} />
 *   <Checkbox value="option2" label={{ children: "Option 2" }} />
 * </CheckboxGroup>
 *
 * @example
 * // With validation error
 * <CheckboxGroup invalid aria-label="Options">
 *   <Checkbox value="option1" label={{ children: "Option 1" }} />
 * </CheckboxGroup>
 */
export const CheckboxGroup = forwardRef<HTMLDivElement, CheckboxGroupProps>(
  ({ disabled, invalid, required, readOnly, ...props }, ref) => {
    return (
      <AriaCheckboxGroup
        ref={ref}
        {...(disabled !== undefined && { isDisabled: disabled })}
        {...(invalid !== undefined && { isInvalid: invalid })}
        {...(required !== undefined && { isRequired: required })}
        {...(readOnly !== undefined && { isReadOnly: readOnly })}
        {...props}
      />
    );
  }
);

CheckboxGroup.displayName = "CheckboxGroup";
