import { useContext } from "react";
import { CheckboxGroupStateContext } from "./CheckboxGroup";

/**
 * Hook to access the CheckboxGroup context.
 * Throws an error if used outside of a CheckboxGroup.
 *
 * @returns The CheckboxGroupState from the parent CheckboxGroup
 * @throws Error if used outside of a CheckboxGroup
 *
 * @example
 * const state = useCheckboxGroupContext();
 * const isSelected = state.isSelected("option1");
 *
 * @example
 * const state = useCheckboxGroupContext();
 * // Throws: "useCheckboxGroupContext must be used within a CheckboxGroup"
 */
export function useCheckboxGroupContext() {
  const state = useContext(CheckboxGroupStateContext);

  if (!state) {
    throw new Error(
      `useCheckboxGroupContext must be used within a CheckboxGroup`
    );
  }

  return state;
}
